// Script: generar_73_fix_prevencion_acordeon.js
// Fix: cada seccion de acordeon en Prevencion tiene ahora un boton
// "+ Agregar" en su header, visible siempre (aunque ya haya registros).
// Antes solo aparecia cuando no habia ningun registro, porque el boton
// global del header fue removido al migrar a acordeones.

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/prevencion/page.tsx', "");
escribir('app/analisis/page.tsx', "");
